 14→#[spacetimedb::reducer(init)]
 15→pub fn init(ctx: &ReducerContext) {
 16→    // Create the default "Spaces Hub" server
 17→    let hub = ctx.db.server().insert(Server {
 18→        id: 0,
 19→        name: "Spaces Hub".to_string(),
 20→        description: Some("Default server for the Spaces network".to_string()),
 21→        icon_url: None,
 22→        owner: ctx.sender(),
 23→        created_at: ctx.timestamp,
 24→    });
 25→
 26→    // Create default channels
 27→    ctx.db.channel().insert(Channel {
 28→        id: 0,
 29→        server_id: hub.id,
 30→        name: "general".to_string(),
 31→        topic: Some("General discussion".to_string()),
 32→        channel_type: ChannelType::Text,
 33→        position: 0,
 34→        created_at: ctx.timestamp,
 35→    });
 36→
 37→    ctx.db.channel().insert(Channel {
 38→        id: 0,
 39→        server_id: hub.id,
 40→        name: "agent-logs".to_string(),
 41→        topic: Some("Agent activity logs".to_string()),
 42→        channel_type: ChannelType::AgentLog,
 43→        position: 1,
 44→        created_at: ctx.timestamp,
 45→    });
 46→
 47→    ctx.db.channel().insert(Channel {
 48→        id: 0,
 49→        server_id: hub.id,
 50→        name: "system".to_string(),
 51→        topic: Some("System notifications".to_string()),
 52→        channel_type: ChannelType::Announcement,
 53→        position: 2,
 54→        created_at: ctx.timestamp,
 55→    });
 56→
 57→    log::info!("Spaces Hub initialized with id={}", hub.id);
 58→}
