 60→#[spacetimedb::reducer(client_connected)]
 61→pub fn client_connected(ctx: &ReducerContext) {
 62→    let sender = ctx.sender();
 63→
 64→    // Upsert UserPresence
 65→    if let Some(presence) = ctx.db.user_presence().identity().find(sender) {
 66→        ctx.db.user_presence().identity().update(UserPresence {
 67→            online: true,
 68→            last_seen: ctx.timestamp,
 69→            ..presence
 70→        });
 71→    } else {
 72→        ctx.db.user_presence().insert(UserPresence {
 73→            identity: sender,
 74→            online: true,
 75→            status_text: None,
 76→            last_seen: ctx.timestamp,
 77→        });
 78→    }
 79→
 80→    // Create UserProfile if new
 81→    if ctx.db.user_profile().identity().find(sender).is_none() {
 82→        let short_id = sender.to_hex().to_string();
 83→        let username = format!("user_{}", &short_id[..8.min(short_id.len())]);
 84→
 85→        ctx.db.user_profile().insert(UserProfile {
 86→            identity: sender,
 87→            username,
 88→            display_name: None,
 89→            avatar_url: None,
 90→            bio: None,
 91→            is_agent: false,
 92→            created_at: ctx.timestamp,
 93→        });
 94→
 95→        // Auto-join the Spaces Hub (first server, id=1 typically)
 96→        // Find the Spaces Hub by name
 97→        if let Some(hub) = ctx.db.server().iter().find(|s| s.name == "Spaces Hub") {
 98→            // Only join if not already a member
 99→            let already_member = ctx.db.server_member().server_id().filter(&hub.id)
100→                .any(|m| m.identity == sender);
101→            if !already_member {
102→                ctx.db.server_member().insert(ServerMember {
103→                    id: 0,
104→                    server_id: hub.id,
105→                    identity: sender,
106→                    role: MemberRole::Member,
107→                    joined_at: ctx.timestamp,
108→                });
109→            }
110→        }
111→    }
112→
113→    log::info!("Client connected: {:?}", sender);
114→}
115→
116→#[spacetimedb::reducer(client_disconnected)]
117→pub fn client_disconnected(ctx: &ReducerContext) {
118→    if let Some(presence) = ctx.db.user_presence().identity().find(ctx.sender()) {
119→        ctx.db.user_presence().identity().update(UserPresence {
120→            online: false,
121→            last_seen: ctx.timestamp,
122→            ..presence
123→        });
124→    }
125→    log::info!("Client disconnected: {:?}", ctx.sender());
126→}
