 3→#[derive(SpacetimeType, Clone, Debug, PartialEq)]
 4→pub enum MemberRole {
 5→    Owner,
 6→    Admin,
 7→    Moderator,
 8→    Member,
 9→    Agent,
10→}
11→
12→impl MemberRole {
13→    /// Returns a numeric level for role hierarchy comparison.
14→    /// Higher = more privileged.
15→    pub fn level(&self) -> u8 {
16→        match self {
17→            MemberRole::Owner => 4,
18→            MemberRole::Admin => 3,
19→            MemberRole::Moderator => 2,
20→            MemberRole::Member => 1,
21→            MemberRole::Agent => 1,
22→        }
23→    }
24→}
25→
26→#[derive(SpacetimeType, Clone, Debug, PartialEq)]
27→pub enum ChannelType {
28→    Text,
29→    Voice,
30→    Announcement,
31→    AgentLog,
32→}
33→
34→#[derive(SpacetimeType, Clone, Debug, PartialEq)]
35→pub enum MessageType {
36→    Text,
37→    System,
38→    AgentEvent,
39→    Join,
40→    Leave,
41→}
