 1→use spacetimedb::{Identity, ReducerContext};
 2→
 3→use crate::tables::{channel, server, server_member, Channel, Server, ServerMember};
 4→use crate::types::MemberRole;
 5→
 6→/// Get a user's membership in a server, if any.
 7→pub fn get_membership(ctx: &ReducerContext, server_id: u64, identity: Identity) -> Option<ServerMember> {
 8→    ctx.db
 9→        .server_member()
10→        .server_id()
11→        .filter(&server_id)
12→        .find(|m| m.identity == identity)
13→}
14→
15→/// Get the role of a user in a server.
16→pub fn get_member_role(ctx: &ReducerContext, server_id: u64, identity: Identity) -> Option<MemberRole> {
17→    get_membership(ctx, server_id, identity).map(|m| m.role)
18→}
19→
20→/// Require that the caller is a member of the server. Returns the membership row.
21→pub fn require_member(ctx: &ReducerContext, server_id: u64) -> Result<ServerMember, String> {
22→    get_membership(ctx, server_id, ctx.sender())
23→        .ok_or_else(|| "You are not a member of this server".to_string())
24→}
25→
26→/// Require that the caller has at least the given role level.
27→pub fn require_role(ctx: &ReducerContext, server_id: u64, min_role: MemberRole) -> Result<ServerMember, String> {
28→    let member = require_member(ctx, server_id)?;
29→    if member.role.level() >= min_role.level() {
30→        Ok(member)
31→    } else {
32→        Err(format!("Insufficient permissions: requires {:?} or higher", min_role))
33→    }
34→}
35→
36→/// Look up a channel and its parent server. Returns (Channel, Server).
37→pub fn get_server_for_channel(ctx: &ReducerContext, channel_id: u64) -> Result<(Channel, Server), String> {
38→    let channel = ctx
39→        .db
40→        .channel()
41→        .id()
42→        .find(channel_id)
43→        .ok_or("Channel not found")?;
44→    let server = ctx
45→        .db
46→        .server()
47→        .id()
48→        .find(channel.server_id)
49→        .ok_or("Server not found for channel")?;
50→    Ok((channel, server))
51→}
