 10→#[reducer]
 11→pub fn create_server(ctx: &ReducerContext, name: String, description: Option<String>) -> Result<(), String> {
 12→    if name.is_empty() {
 13→        return Err("Server name cannot be empty".to_string());
 14→    }
 15→    if name.len() > 100 {
 16→        return Err("Server name must be 100 characters or fewer".to_string());
 17→    }
 18→
 19→    // Ensure user has a profile
 20→    ctx.db.user_profile().identity().find(ctx.sender())
 21→        .ok_or("Must be connected to create a server")?;
 22→
 23→    let server = ctx.db.server().insert(Server {
 24→        id: 0,
 25→        name,
 26→        description,
 27→        icon_url: None,
 28→        owner: ctx.sender(),
 29→        created_at: ctx.timestamp,
 30→    });
 31→
 32→    // Add owner as member
 33→    ctx.db.server_member().insert(ServerMember {
 34→        id: 0,
 35→        server_id: server.id,
 36→        identity: ctx.sender(),
 37→        role: MemberRole::Owner,
 38→        joined_at: ctx.timestamp,
 39→    });
 40→
 41→    // Create default #general channel
 42→    ctx.db.channel().insert(Channel {
 43→        id: 0,
 44→        server_id: server.id,
 45→        name: "general".to_string(),
 46→        topic: Some("General discussion".to_string()),
 47→        channel_type: ChannelType::Text,
 48→        position: 0,
 49→        created_at: ctx.timestamp,
 50→    });
 51→
 52→    log::info!("Server '{}' (id={}) created by {:?}", server.name, server.id, ctx.sender());
 53→    Ok(())
 54→}
