 56→#[reducer]
 57→pub fn update_server(
 58→    ctx: &ReducerContext,
 59→    server_id: u64,
 60→    name: Option<String>,
 61→    description: Option<String>,
 62→) -> Result<(), String> {
 63→    auth::require_role(ctx, server_id, MemberRole::Admin)?;
 64→
 65→    let server = ctx.db.server().id().find(server_id)
 66→        .ok_or("Server not found")?;
 67→
 68→    let new_name = name.unwrap_or(server.name.clone());
 69→    if new_name.is_empty() {
 70→        return Err("Server name cannot be empty".to_string());
 71→    }
 72→
 73→    ctx.db.server().id().update(Server {
 74→        name: new_name,
 75→        description: description.or(server.description.clone()),
 76→        ..server
 77→    });
 78→
 79→    Ok(())
 80→}
 81→
 82→#[reducer]
 83→pub fn delete_server(ctx: &ReducerContext, server_id: u64) -> Result<(), String> {
 84→    let server = ctx.db.server().id().find(server_id)
 85→        .ok_or("Server not found")?;
 86→
 87→    if server.owner != ctx.sender() {
 88→        return Err("Only the server owner can delete the server".to_string());
 89→    }
 90→
 91→    // Cascade delete: messages, channels, members
 92→    let channels: Vec<_> = ctx.db.channel().server_id().filter(&server_id).collect();
 93→    for ch in &channels {
 94→        let messages: Vec<_> = ctx.db.message().channel_id().filter(&ch.id).collect();
 95→        for msg in &messages {
 96→            // Delete reactions for this message
 97→            let reactions: Vec<_> = ctx.db.reaction().message_id().filter(&msg.id).collect();
 98→            for r in &reactions {
 99→                ctx.db.reaction().id().delete(&r.id);
100→            }
101→            ctx.db.message().id().delete(&msg.id);
102→        }
103→        // Delete threads
104→        let threads: Vec<_> = ctx.db.thread().channel_id().filter(&ch.id).collect();
105→        for t in &threads {
106→            ctx.db.thread().id().delete(&t.id);
107→        }
108→        ctx.db.channel().id().delete(&ch.id);
109→    }
110→
111→    // Delete members
112→    let members: Vec<_> = ctx.db.server_member().server_id().filter(&server_id).collect();
113→    for m in &members {
114→        ctx.db.server_member().id().delete(&m.id);
115→    }
116→
117→    ctx.db.server().id().delete(&server_id);
118→    log::info!("Server {} deleted by {:?}", server_id, ctx.sender());
119→    Ok(())
120→}
