122→#[reducer]
123→pub fn join_server(ctx: &ReducerContext, server_id: u64) -> Result<(), String> {
124→    ctx.db.server().id().find(server_id)
125→        .ok_or("Server not found")?;
126→
127→    ctx.db.user_profile().identity().find(ctx.sender())
128→        .ok_or("Must be connected to join a server")?;
129→
130→    // Check not already a member
131→    if auth::get_membership(ctx, server_id, ctx.sender()).is_some() {
132→        return Err("Already a member of this server".to_string());
133→    }
134→
135→    let is_agent = ctx.db.user_profile().identity().find(ctx.sender())
136→        .map(|p| p.is_agent)
137→        .unwrap_or(false);
138→
139→    let role = if is_agent { MemberRole::Agent } else { MemberRole::Member };
140→
141→    ctx.db.server_member().insert(ServerMember {
142→        id: 0,
143→        server_id,
144→        identity: ctx.sender(),
145→        role,
146→        joined_at: ctx.timestamp,
147→    });
148→
149→    // Post a system join message in general channel
150→    if let Some(general) = ctx.db.channel().server_id().filter(&server_id)
151→        .find(|c| c.name == "general")
152→    {
153→        let profile = ctx.db.user_profile().identity().find(ctx.sender());
154→        let name = profile.map(|p| p.username).unwrap_or_else(|| "Unknown".to_string());
155→        ctx.db.message().insert(Message {
156→            id: 0,
157→            channel_id: general.id,
158→            thread_id: None,
159→            sender: ctx.sender(),
160→            content: format!("{} joined the server", name),
161→            message_type: MessageType::Join,
162→            created_at: ctx.timestamp,
163→            edited_at: None,
164→            reply_to_id: None,
165→        });
166→    }
167→
168→    Ok(())
169→}
