171→#[reducer]
172→pub fn leave_server(ctx: &ReducerContext, server_id: u64) -> Result<(), String> {
173→    let server = ctx.db.server().id().find(server_id)
174→        .ok_or("Server not found")?;
175→
176→    if server.owner == ctx.sender() {
177→        return Err("Server owner cannot leave. Transfer ownership or delete the server.".to_string());
178→    }
179→
180→    let member = auth::require_member(ctx, server_id)?;
181→    ctx.db.server_member().id().delete(&member.id);
182→
183→    // Post a system leave message
184→    if let Some(general) = ctx.db.channel().server_id().filter(&server_id)
185→        .find(|c| c.name == "general")
186→    {
187→        let profile = ctx.db.user_profile().identity().find(ctx.sender());
188→        let name = profile.map(|p| p.username).unwrap_or_else(|| "Unknown".to_string());
189→        ctx.db.message().insert(Message {
190→            id: 0,
191→            channel_id: general.id,
192→            thread_id: None,
193→            sender: ctx.sender(),
194→            content: format!("{} left the server", name),
195→            message_type: MessageType::Leave,
196→            created_at: ctx.timestamp,
197→            edited_at: None,
198→            reply_to_id: None,
199→        });
200→    }
201→
202→    Ok(())
203→}
