205→#[reducer]
206→pub fn update_member_role(
207→    ctx: &ReducerContext,
208→    server_id: u64,
209→    target_identity: spacetimedb::Identity,
210→    new_role: MemberRole,
211→) -> Result<(), String> {
212→    let actor = auth::require_member(ctx, server_id)?;
213→    let target = auth::get_membership(ctx, server_id, target_identity)
214→        .ok_or("Target is not a member of this server")?;
215→
216→    // Cannot change owner role
217→    if target.role == MemberRole::Owner {
218→        return Err("Cannot change the owner's role".to_string());
219→    }
220→    if new_role == MemberRole::Owner {
221→        return Err("Cannot assign Owner role. Use transfer ownership instead.".to_string());
222→    }
223→
224→    // Actor must outrank the target's current role AND the new role
225→    if actor.role.level() <= target.role.level() {
226→        return Err("Cannot modify role of someone with equal or higher rank".to_string());
227→    }
228→    if actor.role.level() <= new_role.level() {
229→        return Err("Cannot assign a role equal to or higher than your own".to_string());
230→    }
231→
232→    ctx.db.server_member().id().update(ServerMember {
233→        role: new_role,
234→        ..target
235→    });
236→
237→    Ok(())
238→}
