 7→#[reducer]
 8→pub fn create_channel(
 9→    ctx: &ReducerContext,
10→    server_id: u64,
11→    name: String,
12→    channel_type: ChannelType,
13→) -> Result<(), String> {
14→    if name.is_empty() {
15→        return Err("Channel name cannot be empty".to_string());
16→    }
17→    if name.len() > 100 {
18→        return Err("Channel name must be 100 characters or fewer".to_string());
19→    }
20→
21→    auth::require_role(ctx, server_id, MemberRole::Admin)?;
22→
23→    // Determine next position
24→    let max_pos = ctx.db.channel().server_id().filter(&server_id)
25→        .map(|c| c.position)
26→        .max()
27→        .unwrap_or(0);
28→
29→    ctx.db.channel().insert(Channel {
30→        id: 0,
31→        server_id,
32→        name,
33→        topic: None,
34→        channel_type,
35→        position: max_pos + 1,
36→        created_at: ctx.timestamp,
37→    });
38→
39→    Ok(())
40→}
