42→#[reducer]
43→pub fn update_channel(
44→    ctx: &ReducerContext,
45→    channel_id: u64,
46→    name: Option<String>,
47→    topic: Option<String>,
48→) -> Result<(), String> {
49→    let (channel, _server) = auth::get_server_for_channel(ctx, channel_id)?;
50→    auth::require_role(ctx, channel.server_id, MemberRole::Admin)?;
51→
52→    let new_name = name.unwrap_or(channel.name.clone());
53→    if new_name.is_empty() {
54→        return Err("Channel name cannot be empty".to_string());
55→    }
56→
57→    ctx.db.channel().id().update(Channel {
58→        name: new_name,
59→        topic: topic.or(channel.topic.clone()),
60→        ..channel
61→    });
62→
63→    Ok(())
64→}
65→
66→#[reducer]
67→pub fn delete_channel(ctx: &ReducerContext, channel_id: u64) -> Result<(), String> {
68→    let (channel, _server) = auth::get_server_for_channel(ctx, channel_id)?;
69→    auth::require_role(ctx, channel.server_id, MemberRole::Admin)?;
70→
71→    // Cascade delete messages and reactions
72→    let messages: Vec<_> = ctx.db.message().channel_id().filter(&channel_id).collect();
73→    for msg in &messages {
74→        let reactions: Vec<_> = ctx.db.reaction().message_id().filter(&msg.id).collect();
75→        for r in &reactions {
76→            ctx.db.reaction().id().delete(&r.id);
77→        }
78→        ctx.db.message().id().delete(&msg.id);
79→    }
80→
81→    // Delete threads
82→    let threads: Vec<_> = ctx.db.thread().channel_id().filter(&channel_id).collect();
83→    for t in &threads {
84→        ctx.db.thread().id().delete(&t.id);
85→    }
86→
87→    ctx.db.channel().id().delete(&channel_id);
88→    Ok(())
89→}
