 10→#[reducer]
 11→pub fn send_message(
 12→    ctx: &ReducerContext,
 13→    channel_id: u64,
 14→    content: String,
 15→    thread_id: Option<u64>,
 16→    reply_to_id: Option<u64>,
 17→) -> Result<(), String> {
 18→    if content.is_empty() {
 19→        return Err("Message content cannot be empty".to_string());
 20→    }
 21→    if content.len() > 4000 {
 22→        return Err("Message must be 4000 characters or fewer".to_string());
 23→    }
 24→
 25→    let (channel, _server) = auth::get_server_for_channel(ctx, channel_id)?;
 26→    auth::require_member(ctx, channel.server_id)?;
 27→
 28→    // Validate thread exists if specified
 29→    if let Some(tid) = thread_id {
 30→        let thread = ctx.db.thread().id().find(tid)
 31→            .ok_or("Thread not found")?;
 32→        if thread.archived {
 33→            return Err("Cannot post in an archived thread".to_string());
 34→        }
 35→        if thread.channel_id != channel_id {
 36→            return Err("Thread does not belong to this channel".to_string());
 37→        }
 38→        // Update thread's last_message_at
 39→        ctx.db.thread().id().update(Thread {
 40→            last_message_at: ctx.timestamp,
 41→            ..thread
 42→        });
 43→    }
 44→
 45→    // Validate reply target exists if specified
 46→    if let Some(rid) = reply_to_id {
 47→        ctx.db.message().id().find(rid)
 48→            .ok_or("Reply target message not found")?;
 49→    }
 50→
 51→    ctx.db.message().insert(Message {
 52→        id: 0,
 53→        channel_id,
 54→        thread_id,
 55→        sender: ctx.sender(),
 56→        content,
 57→        message_type: MessageType::Text,
 58→        created_at: ctx.timestamp,
 59→        edited_at: None,
 60→        reply_to_id,
 61→    });
 62→
 63→    Ok(())
 64→}
 65→
 66→#[reducer]
 67→pub fn edit_message(ctx: &ReducerContext, message_id: u64, new_content: String) -> Result<(), String> {
 68→    if new_content.is_empty() {
 69→        return Err("Message content cannot be empty".to_string());
 70→    }
 71→    if new_content.len() > 4000 {
 72→        return Err("Message must be 4000 characters or fewer".to_string());
 73→    }
 74→
 75→    let msg = ctx.db.message().id().find(message_id)
 76→        .ok_or("Message not found")?;
 77→
 78→    if msg.sender != ctx.sender() {
 79→        return Err("You can only edit your own messages".to_string());
 80→    }
 81→
 82→    ctx.db.message().id().update(Message {
 83→        content: new_content,
 84→        edited_at: Some(ctx.timestamp),
 85→        ..msg
 86→    });
 87→
 88→    Ok(())
 89→}
 90→
 91→#[reducer]
 92→pub fn delete_message(ctx: &ReducerContext, message_id: u64) -> Result<(), String> {
 93→    let msg = ctx.db.message().id().find(message_id)
 94→        .ok_or("Message not found")?;
 95→
 96→    let is_sender = msg.sender == ctx.sender();
 97→
 98→    // Check if admin+ in the server
 99→    let (_channel, _server) = auth::get_server_for_channel(ctx, msg.channel_id)?;
100→    let is_admin = auth::get_member_role(ctx, _channel.server_id, ctx.sender())
101→        .map(|r| r.level() >= MemberRole::Admin.level())
102→        .unwrap_or(false);
103→
104→    if !is_sender && !is_admin {
105→        return Err("You can only delete your own messages, or be an admin".to_string());
106→    }
107→
108→    // Delete reactions first
109→    let reactions: Vec<_> = ctx.db.reaction().message_id().filter(&message_id).collect();
110→    for r in &reactions {
111→        ctx.db.reaction().id().delete(&r.id);
112→    }
113→
114→    ctx.db.message().id().delete(&message_id);
115→    Ok(())
116→}
117→
118→#[reducer]
119→pub fn add_reaction(ctx: &ReducerContext, message_id: u64, emoji: String) -> Result<(), String> {
120→    if emoji.is_empty() {
121→        return Err("Emoji cannot be empty".to_string());
122→    }
123→
124→    let msg = ctx.db.message().id().find(message_id)
125→        .ok_or("Message not found")?;
126→
127→    // Verify membership
128→    let (channel, _server) = auth::get_server_for_channel(ctx, msg.channel_id)?;
129→    auth::require_member(ctx, channel.server_id)?;
130→
131→    // Check for duplicate reaction
132→    let already = ctx.db.reaction().message_id().filter(&message_id)
133→        .any(|r| r.identity == ctx.sender() && r.emoji == emoji);
134→    if already {
135→        return Err("You already reacted with this emoji".to_string());
136→    }
137→
138→    ctx.db.reaction().insert(Reaction {
139→        id: 0,
140→        message_id,
141→        identity: ctx.sender(),
142→        emoji,
143→    });
144→
145→    Ok(())
146→}
147→
148→#[reducer]
149→pub fn remove_reaction(ctx: &ReducerContext, message_id: u64, emoji: String) -> Result<(), String> {
150→    let reaction = ctx.db.reaction().message_id().filter(&message_id)
151→        .find(|r| r.identity == ctx.sender() && r.emoji == emoji)
152→        .ok_or("Reaction not found")?;
153→
154→    ctx.db.reaction().id().delete(&reaction.id);
155→    Ok(())
156→}
157→
158→#[reducer]
159→pub fn start_typing(ctx: &ReducerContext, channel_id: u64) -> Result<(), String> {
160→    let (channel, _server) = auth::get_server_for_channel(ctx, channel_id)?;
161→    auth::require_member(ctx, channel.server_id)?;
162→
163→    ctx.db.typing_indicator().insert(TypingIndicator {
164→        id: 0,
165→        channel_id,
166→        identity: ctx.sender(),
167→    });
168→
169→    Ok(())
170→}
171→
172→#[reducer]
173→pub fn mark_read(ctx: &ReducerContext, channel_id: u64, message_id: u64) -> Result<(), String> {
174→    // Find existing read state for this user+channel
175→    let existing = ctx.db.channel_read_state().identity().filter(&ctx.sender())
176→        .find(|rs| rs.channel_id == channel_id);
177→
178→    if let Some(rs) = existing {
179→        ctx.db.channel_read_state().id().update(ChannelReadState {
180→            last_read_msg_id: message_id,
181→            ..rs
182→        });
183→    } else {
184→        ctx.db.channel_read_state().insert(ChannelReadState {
185→            id: 0,
186→            identity: ctx.sender(),
187→            channel_id,
188→            last_read_msg_id: message_id,
189→        });
190→    }
191→
192→    Ok(())
193→}
