 1→use spacetimedb::{reducer, ReducerContext, Table};
 2→
 3→use crate::auth;
 4→use crate::tables::{message, thread, Message, Thread};
 5→use crate::types::MessageType;
 6→
 7→#[reducer]
 8→pub fn create_thread(
 9→    ctx: &ReducerContext,
10→    channel_id: u64,
11→    name: String,
12→    initial_message: String,
13→) -> Result<(), String> {
14→    if name.is_empty() {
15→        return Err("Thread name cannot be empty".to_string());
16→    }
17→    if initial_message.is_empty() {
18→        return Err("Initial message cannot be empty".to_string());
19→    }
20→
21→    let (channel, _server) = auth::get_server_for_channel(ctx, channel_id)?;
22→    auth::require_member(ctx, channel.server_id)?;
23→
24→    let thread = ctx.db.thread().insert(Thread {
25→        id: 0,
26→        channel_id,
27→        name,
28→        creator: ctx.sender(),
29→        created_at: ctx.timestamp,
30→        archived: false,
31→        last_message_at: ctx.timestamp,
32→    });
33→
34→    // Insert the initial message in the thread
35→    ctx.db.message().insert(Message {
36→        id: 0,
37→        channel_id,
38→        thread_id: Some(thread.id),
39→        sender: ctx.sender(),
40→        content: initial_message,
41→        message_type: MessageType::Text,
42→        created_at: ctx.timestamp,
43→        edited_at: None,
44→        reply_to_id: None,
45→    });
46→
47→    Ok(())
48→}
49→
50→#[reducer]
51→pub fn archive_thread(ctx: &ReducerContext, thread_id: u64) -> Result<(), String> {
52→    let thread = ctx.db.thread().id().find(thread_id)
53→        .ok_or("Thread not found")?;
54→
55→    let (channel, _server) = auth::get_server_for_channel(ctx, thread.channel_id)?;
56→
57→    // Creator or admin+ can archive
58→    let is_creator = thread.creator == ctx.sender();
59→    let is_admin = auth::get_member_role(ctx, channel.server_id, ctx.sender())
60→        .map(|r| r.level() >= crate::types::MemberRole::Admin.level())
61→        .unwrap_or(false);
62→
63→    if !is_creator && !is_admin {
64→        return Err("Only the thread creator or an admin can archive a thread".to_string());
65→    }
66→
67→    ctx.db.thread().id().update(Thread {
68→        archived: true,
69→        ..thread
70→    });
71→
72→    Ok(())
73→}
