 1→use spacetimedb::{reducer, ReducerContext};
 2→
 3→use crate::tables::{user_profile, UserProfile};
 4→
 5→#[reducer]
 6→pub fn set_profile(
 7→    ctx: &ReducerContext,
 8→    username: String,
 9→    display_name: Option<String>,
10→    avatar_url: Option<String>,
11→    bio: Option<String>,
12→) -> Result<(), String> {
13→    if username.is_empty() {
14→        return Err("Username cannot be empty".to_string());
15→    }
16→    if username.len() > 32 {
17→        return Err("Username must be 32 characters or fewer".to_string());
18→    }
19→
20→    let profile = ctx.db.user_profile().identity().find(ctx.sender())
21→        .ok_or("User profile not found. Connect first.")?;
22→
23→    // Check username uniqueness (if changing)
24→    if profile.username != username {
25→        if ctx.db.user_profile().username().find(&username).is_some() {
26→            return Err(format!("Username '{}' is already taken", username));
27→        }
28→    }
29→
30→    ctx.db.user_profile().identity().update(UserProfile {
31→        username,
32→        display_name,
33→        avatar_url,
34→        bio,
35→        ..profile
36→    });
37→
38→    Ok(())
39→}
