41→#[reducer]
42→pub fn register_agent(
43→    ctx: &ReducerContext,
44→    agent_name: String,
45→    description: String,
46→) -> Result<(), String> {
47→    if agent_name.is_empty() {
48→        return Err("Agent name cannot be empty".to_string());
49→    }
50→
51→    let profile = ctx.db.user_profile().identity().find(ctx.sender())
52→        .ok_or("User profile not found. Connect first.")?;
53→
54→    if profile.is_agent {
55→        return Err("Already registered as an agent".to_string());
56→    }
57→
58→    // Check username uniqueness if changing
59→    if profile.username != agent_name {
60→        if ctx.db.user_profile().username().find(&agent_name).is_some() {
61→            return Err(format!("Name '{}' is already taken", agent_name));
62→        }
63→    }
64→
65→    ctx.db.user_profile().identity().update(UserProfile {
66→        username: agent_name,
67→        bio: Some(description),
68→        is_agent: true,
69→        ..profile
70→    });
71→
72→    Ok(())
73→}
