 37→// --- Connection ---
 38→
 39→fn connect_to_db() -> DbConnection {
 40→    let host = env::var("SPACETIMEDB_HOST")
 41→        .unwrap_or_else(|_| "https://maincloud.spacetimedb.com".to_string());
 42→    let db_name = env::var("SPACETIMEDB_DB_NAME").unwrap_or_else(|_| "spaces".to_string());
 43→
 44→    DbConnection::builder()
 45→        .on_connect(on_connected)
 46→        .on_connect_error(on_connect_error)
 47→        .on_disconnect(on_disconnected)
 48→        .with_token(creds_store().load().ok().flatten())
 49→        .with_database_name(db_name)
 50→        .with_uri(host)
 51→        .build()
 52→        .expect("Failed to connect")
 53→}
 54→
 55→fn creds_store() -> credentials::File {
 56→    credentials::File::new("spaces")
 57→}
 58→
 59→fn on_connected(_ctx: &DbConnection, identity: Identity, token: &str) {
 60→    if let Err(e) = creds_store().save(token) {
 61→        eprintln!("Failed to save credentials: {e:?}");
 62→    }
 63→    println!("Connected as: {}", identity.to_abbreviated_hex());
 64→}
 65→
 66→fn on_connect_error(_ctx: &ErrorContext, err: Error) {
 67→    eprintln!("Connection error: {err}");
 68→    std::process::exit(1);
 69→}
 70→
 71→fn on_disconnected(_ctx: &ErrorContext, err: Option<Error>) {
 72→    if let Some(err) = err {
 73→        eprintln!("Disconnected: {err}");
 74→        std::process::exit(1);
 75→    } else {
 76→        println!("Disconnected.");
 77→        std::process::exit(0);
 78→    }
 79→}
