 81→// --- Callbacks ---
 82→
 83→fn register_callbacks(ctx: &DbConnection) {
 84→    ctx.db.user_profile().on_insert(on_user_profile_inserted);
 85→    ctx.db.user_presence().on_update(on_user_presence_updated);
 86→    ctx.db.message().on_insert(on_message_inserted);
 87→    ctx.db.server().on_insert(on_server_inserted);
 88→    ctx.db.channel().on_insert(on_channel_inserted);
 89→}
