139→// --- Helpers ---
140→
141→fn user_display_name(ctx: &impl RemoteDbContext, identity: &Identity) -> String {
142→    ctx.db()
143→        .user_profile()
144→        .identity()
145→        .find(identity)
146→        .map(|p| p.display_name.clone().unwrap_or_else(|| p.username.clone()))
147→        .unwrap_or_else(|| identity.to_abbreviated_hex().to_string())
148→}
