150→fn print_message(ctx: &impl RemoteDbContext, msg: &Message) {
151→    let sender = user_display_name(ctx, &msg.sender);
152→    let type_prefix = match msg.message_type {
153→        MessageType::System => "[SYSTEM] ",
154→        MessageType::Join => "[JOIN] ",
155→        MessageType::Leave => "[LEAVE] ",
156→        MessageType::AgentEvent => "[AGENT] ",
157→        MessageType::Text => "",
158→    };
159→    let thread_suffix = msg
160→        .thread_id
161→        .map(|t| format!(" (thread:{})", t))
162→        .unwrap_or_default();
163→    let reply_suffix = msg
164→        .reply_to_id
165→        .map(|r| format!(" (reply to:{})", r))
166→        .unwrap_or_default();
167→    let edit_mark = if msg.edited_at.is_some() {
168→        " (edited)"
169→    } else {
170→        ""
171→    };
172→    println!(
173→        "{}{}: {}{}{}{}",
174→        type_prefix, sender, msg.content, thread_suffix, reply_suffix, edit_mark
175→    );
176→}
