178→// --- Subscriptions ---
179→
180→fn subscribe_to_tables(ctx: &DbConnection) {
181→    ctx.subscription_builder()
182→        .on_applied(on_sub_applied)
183→        .on_error(on_sub_error)
184→        .subscribe_to_all_tables();
185→}
186→
187→fn on_sub_applied(ctx: &SubscriptionEventContext) {
188→    println!("\n=== Spaces - Discord Clone on SpacetimeDB ===\n");
189→
190→    // List servers
191→    let servers: Vec<_> = ctx.db.server().iter().collect();
192→    if servers.is_empty() {
193→        println!("No servers found.");
194→    } else {
195→        println!("Servers:");
196→        for s in &servers {
197→            println!("  [{}] {}", s.id, s.name);
198→        }
199→    }
200→
201→    // Auto-select first server
202→    if let Some(first) = servers.first() {
203→        CURRENT_SERVER_ID.store(first.id, Ordering::Relaxed);
204→        println!("\nActive server: {} (id={})", first.name, first.id);
205→
206→        // Show channels
207→        let channels: Vec<_> = ctx
208→            .db
209→            .channel()
210→            .iter()
211→            .filter(|c| c.server_id == first.id)
212→            .collect();
213→        if !channels.is_empty() {
214→            println!("Channels:");
215→            for ch in &channels {
216→                println!("  [{}] #{} ({:?})", ch.id, ch.name, ch.channel_type);
217→            }
218→            // Auto-select first text channel
219→            if let Some(text_ch) = channels
220→                .iter()
221→                .find(|c| c.channel_type == ChannelType::Text)
222→            {
223→                CURRENT_CHANNEL_ID.store(text_ch.id, Ordering::Relaxed);
224→                println!("\nActive channel: #{} (id={})", text_ch.name, text_ch.id);
225→
226→                // Show recent messages
227→                let mut msgs: Vec<_> = ctx
228→                    .db
229→                    .message()
230→                    .iter()
231→                    .filter(|m| m.channel_id == text_ch.id && m.thread_id.is_none())
232→                    .collect();
233→                msgs.sort_by_key(|m| m.created_at);
234→                let recent: Vec<_> = msgs
235→                    .iter()
236→                    .rev()
237→                    .take(25)
238→                    .collect::<Vec<_>>()
239→                    .into_iter()
240→                    .rev()
241→                    .collect();
242→                if !recent.is_empty() {
243→                    println!("\n--- Recent messages ---");
244→                    for msg in recent {
245→                        print_message(ctx, msg);
246→                    }
247→                    println!("--- End ---\n");
248→                }
249→            }
250→        }
251→    }
252→
253→    println!("Type /help for commands, or type a message to send.");
254→    println!();
255→    READY.store(true, Ordering::Release);
256→}
257→
258→fn on_sub_error(_ctx: &ErrorContext, err: Error) {
259→    eprintln!("Subscription failed: {err}");
260→    std::process::exit(1);
261→}
262→
263→// --- User Input ---
264→
265→fn user_input_loop(ctx: &DbConnection) {
266→    // Wait for subscription to be applied before processing input
267→    while !READY.load(Ordering::Acquire) {
268→        std::thread::sleep(std::time::Duration::from_millis(50));
269→    }
270→    for line in std::io::stdin().lines() {
271→        let Ok(line) = line else {
272→            break;
273→        };
274→        let line = line.trim().to_string();
275→        if line.is_empty() {
276→            continue;
277→        }
278→
279→        if line.starts_with('/') {
280→            handle_command(ctx, &line);
281→        } else {
282→            // Send message to current channel
283→            if let Some(ch_id) = current_channel() {
284→                if let Err(e) = ctx.reducers.send_message(ch_id, line, None, None) {
285→                    eprintln!("Failed to send: {e}");
286→                }
287→            } else {
288→                eprintln!("No channel selected. Use /channel <id> to select one.");
289→            }
290→        }
291→    }
292→}
293→
294→fn handle_command(ctx: &DbConnection, input: &str) {
295→    let parts: Vec<&str> = input.splitn(2, ' ').collect();
296→    let cmd = parts[0];
297→    let arg = parts.get(1).map(|s| s.trim()).unwrap_or("");
298→
299→    match cmd {
300→        "/help" => print_help(),
301→        "/name" => cmd_set_name(ctx, arg),
302→        "/servers" => cmd_list_servers(ctx),
303→        "/server" => cmd_select_server(ctx, arg),
304→        "/join" => cmd_join_server(ctx, arg),
305→        "/leave" => cmd_leave_server(ctx, arg),
306→        "/create-server" => cmd_create_server(ctx, arg),
307→        "/channels" => cmd_list_channels(ctx),
308→        "/channel" => cmd_select_channel(ctx, arg),
309→        "/create-channel" => cmd_create_channel(ctx, arg),
310→        "/threads" => cmd_list_threads(ctx),
311→        "/thread" => cmd_create_thread(ctx, arg),
312→        "/members" => cmd_list_members(ctx),
313→        "/react" => cmd_react(ctx, arg),
314→        "/agent" => cmd_register_agent(ctx, arg),
315→        "/who" => cmd_who(ctx),
316→        "/history" => cmd_history(ctx, arg),
317→        _ => eprintln!("Unknown command: {cmd}. Type /help for available commands."),
318→    }
319→}
