359→fn cmd_set_name(ctx: &DbConnection, arg: &str) {
360→    if arg.is_empty() {
361→        eprintln!("Usage: /name <username>");
362→        return;
363→    }
364→    if let Err(e) = ctx.reducers.set_profile(arg.to_string(), None, None, None) {
365→        eprintln!("Failed to set profile: {e}");
366→    } else {
367→        println!("Username set to: {}", arg);
368→    }
369→}
