371→fn cmd_list_servers(ctx: &DbConnection) {
372→    let servers: Vec<_> = ctx.db.server().iter().collect();
373→    if servers.is_empty() {
374→        println!("No servers found.");
375→        return;
376→    }
377→    println!("Servers:");
378→    for s in &servers {
379→        let marker = if current_server() == Some(s.id) {
380→            " *"
381→        } else {
382→            ""
383→        };
384→        println!("  [{}] {}{}", s.id, s.name, marker);
385→    }
386→}
387→
388→fn cmd_select_server(ctx: &DbConnection, arg: &str) {
389→    if arg.is_empty() {
390→        eprintln!("Usage: /server <id>");
391→        return;
392→    }
393→
394→    // Try by ID first, then by name
395→    let server = if let Ok(id) = arg.parse::<u64>() {
396→        ctx.db.server().id().find(&id)
397→    } else {
398→        ctx.db
399→            .server()
400→            .iter()
401→            .find(|s| s.name.to_lowercase() == arg.to_lowercase())
402→    };
403→
404→    if let Some(s) = server {
405→        CURRENT_SERVER_ID.store(s.id, Ordering::Relaxed);
406→        CURRENT_CHANNEL_ID.store(0, Ordering::Relaxed);
407→        println!("Active server: {} (id={})", s.name, s.id);
408→
409→        // Show channels
410→        cmd_list_channels(ctx);
411→
412→        // Auto-select first text channel
413→        if let Some(ch) = ctx
414→            .db
415→            .channel()
416→            .iter()
417→            .find(|c| c.server_id == s.id && c.channel_type == ChannelType::Text)
418→        {
419→            CURRENT_CHANNEL_ID.store(ch.id, Ordering::Relaxed);
420→            println!("Active channel: #{} (id={})", ch.name, ch.id);
